def demo(n):
    b_n = bin(n)
    index = b_n.rfind('1') + 1
    return len(b_n[index:])

def demo(n):
    if n == 1:
        return 0
    if n == 2:
        return 1
    m, c = divmod(n, 2)
    return m + demo(c + m)

def searchOne(s):
    d = dict()
    for ch in s:
        d[ch] = d.get(ch, 0) + 1
    return [ch for ch, n in d.items() if n == 1]

def bubbleSort(lst):
    length = len(lst)
    for i in range(length):
        flag = True
        for j in range(length - i - 1):
            if lst[j] > lst[j+1]:
                lst[j], lst[j+1] = lst[j+1], lst[j]
                flag = False
        if flag:
            break

def nested(s):
    result = []
    length = len(s)
    index = length % 3
    if index != 0:
        result.append(s[:index])
    for i in range(index, length, 3):
        result.append(s[i:i+3])
    return ','.join(result)
